module RefModule(
	input wire[3:0] num,
	input wire en, dp, sign,
	output wire[7:0] hex
);reg [6:0] unused_sseg;

	always @*
	begin
		if (~en)
			unused_sseg <= 7'b0000000;
		else if (sign)
			unused_sseg <= 7'b1000000;
		else
			case (num)
				4'h0: unused_sseg <= 7'b0111111;
				4'h1: unused_sseg <= 7'b0000110;
				4'h2: unused_sseg <= 7'b1011011;
				4'h3: unused_sseg <= 7'b1001111;
				4'h4: unused_sseg <= 7'b1100110;
				4'h5: unused_sseg <= 7'b1101101;
				4'h6: unused_sseg <= 7'b1111101;
				4'h7: unused_sseg <= 7'b0000111;
				4'h8: unused_sseg <= 7'b1111111;
				4'h9: unused_sseg <= 7'b1101111;
				4'ha: unused_sseg <= 7'b1110111;
				4'hb: unused_sseg <= 7'b1111100;
				4'hc: unused_sseg <= 7'b1011000;
				4'hd: unused_sseg <= 7'b1011110;
				4'he: unused_sseg <= 7'b1111001;
				4'hf: unused_sseg <= 7'b1110001;
				default: unused_sseg <= 7'b1010011;
			endcase
	end

	assign hex = { (dp & en), unused_sseg };

endmodule
